import{_ as t,c as a,a1 as e,o as c}from"./chunks/framework.BDxlaA_J.js";const l=JSON.parse('{"title":"Thu thập tình báo mã nguồn mở sử dụng OSRFramework","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md"}'),i={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md"};function s(r,n,h,o,p,u){return c(),a("div",null,n[0]||(n[0]=[e(`<h1 id="thu-thap-tinh-bao-ma-nguon-mo-su-dung-osrframework" tabindex="-1">Thu thập tình báo mã nguồn mở sử dụng OSRFramework <a class="header-anchor" href="#thu-thap-tinh-bao-ma-nguon-mo-su-dung-osrframework" aria-label="Permalink to &quot;Thu thập tình báo mã nguồn mở sử dụng OSRFramework&quot;">​</a></h1><p>OSRFramework là một tập hợp các thư viện để thực hiện các tác vụ Open Source Intelligence. Chúng bao gồm tham chiếu đến nhiều ứng dụng khác nhau liên quan đến kiểm tra tên người dùng, tra cứu DNS, nghiên cứu rò rỉ thông tin, tìm kiếm deep web, trích xuất biểu thức chính quy và nhiều hơn nữa.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Trình bày cách xác định tên người dùng của mục tiêu trên các nền tảng mạng xã hội khác nhau.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li></ul><hr><ol><li><p>Đăng nhập vào máy <strong>Kali Linux</strong> và mở cửa sổ <strong>Terminal</strong>.</p></li><li><p>Cập nhật APT và cài đặt OSRFramework:</p></li></ol><p><code>apt update &amp;&amp; apt -y install osrframework</code></p><h2 id="su-dung-usufy-py" tabindex="-1">Sử dụng usufy.py <a class="header-anchor" href="#su-dung-usufy-py" aria-label="Permalink to &quot;Sử dụng usufy.py&quot;">​</a></h2><p><code>usufy.py</code> kiểm tra sự tồn tại của hồ sơ cho một chi tiết người dùng nhất định trên các nền tảng khác nhau.</p><p>Cách sử dụng: <strong>usufy.py -n <code>target</code> -p twitter facebook youtube</strong></p><p><code>usufy.py -n cehuser us -p twitter facebook youtube</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>|         i3visio_uri         | i3visio_alias | i3visio_platform |</span></span>
<span class="line"><span>+=============================+===============+==================+</span></span>
<span class="line"><span>| \`http://twitter.com/us\`       | us            | Twitter          |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>| \`https://www.facebook.com/us\` | us            | Facebook         |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>| \`http://twitter.com/cehuser\`  | cehuser       | Twitter          |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span></code></pre></div><p><strong>usufy.py</strong> sẽ tìm kiếm chi tiết người dùng trên nền tảng được đề cập và cung cấp cho bạn thông tin về sự tồn tại của người dùng như hiển thị ở trên.</p><h2 id="su-dung-searchfy-py" tabindex="-1">Sử dụng searchfy.py <a class="header-anchor" href="#su-dung-searchfy-py" aria-label="Permalink to &quot;Sử dụng searchfy.py&quot;">​</a></h2><p><code>searchfy.py</code> kiểm tra với những người dùng hiện có của các trang/handler cho một chi tiết nhất định trên tất cả các mạng xã hội.</p><p>Cách sử dụng: <code>searchfy.py -q &quot;Page Name or Handler Name&quot;</code></p><p><code>searchfy.py -q &quot;ECCouncil&quot;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c07e9574a732bbd239c81d4b1e24bee3de20e62b/searchfy-eccouncil.png" alt="alt text" title="serachfy eccouncil screenshot"></p><p>Nó sẽ trích xuất tất cả chi tiết người dùng đã đăng ký theo dõi các trang mạng xã hội mục tiêu được cung cấp.</p><h2 id="cac-lenh-con-cli-cua-osrframework" tabindex="-1">Các lệnh con CLI của OSRFramework: <a class="header-anchor" href="#cac-lenh-con-cli-cua-osrframework" aria-label="Permalink to &quot;Các lệnh con CLI của OSRFramework:&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Lệnh con</th><th>Mô tả</th></tr></thead><tbody><tr><td>usufy.py</td><td>Công cụ xác minh tên người dùng có tồn tại trên 249 nền tảng mạng xã hội hay không.</td></tr><tr><td>mailfy.py</td><td>Module kiểm tra tên người dùng đã được đăng ký trên tối đa 22 nhà cung cấp email hay không.</td></tr><tr><td>searchfy.py</td><td>Module tìm kiếm hồ sơ bằng tên đầy đủ và thông tin khác trên 7 nền tảng.</td></tr><tr><td>domainfy.py</td><td>Module kiểm tra sự tồn tại của một tên miền nhất định trên tối đa 879 TLD khác nhau.</td></tr><tr><td>phonefy.py</td><td>Module kiểm tra số điện thoại có liên kết với hành vi spam trên 4 nền tảng hay không.</td></tr><tr><td>entify.py</td><td>Module tìm kiếm biểu thức chính quy sử dụng 13 mẫu.</td></tr></tbody></table>`,23)]))}const g=t(i,[["render",s]]);export{l as __pageData,g as default};
